export const DT_TREES={"suicide":{"id":"suicide","title":"Suicide Risk Assessment","category":"safety","domain":"Risk & Safety","description":"Systematic approach to evaluating suicide risk and matching the response to the level of risk.","whatToNotice":"Ideation, plan, access to means, intent, and protective factors. These five stack — each \"yes\" raises acuity. A specific plan with access to means is the highest-weight combination.","whyItMatters":"Safety assessment always precedes every other diagnostic or treatment decision on the NCMHCE. Under-responding is a safety risk; over-responding damages the alliance and can drive a client to under-report. Calibration is the skill being tested.","goldenFormula":"Validate the disclosure (\"Thank you for telling me\"), explore the specifics (plan, means, intent, history, protective factors), then act at the level the risk warrants.","startId":1,"nodes":[{"id":1,"question":"Is the client expressing suicidal ideation?","yes":2,"no":8,"teach":"Ask directly. Asking about suicide does not plant the idea — avoiding it leaves risk unassessed."},{"id":2,"question":"Is there a specific plan?","yes":3,"no":5,"teach":"A specific, detailed plan signals greater acuity than vague or passive ideation."},{"id":3,"question":"Does the client have access to means?","yes":4,"no":5,"teach":"Access converts a plan into immediate lethality. Means restriction is one of the most evidence-based interventions."},{"id":4,"outcome":"HIGH RISK","color":"#EF4444","action":"Consider hospitalization, restrict access to means, arrange constant monitoring, and build a safety plan. Do not leave the client alone.","clinicalNote":"Plan + access (or clear intent) = highest acuity. The exam rewards decisive, least-restrictive-but-adequate action over \"continue to monitor.\""},{"id":5,"question":"Is there intent to act on the thoughts?","yes":4,"no":6,"teach":"Intent is the bridge between thought and action. Ideation without intent is lower acuity than ideation with intent."},{"id":6,"question":"Are protective factors present (reasons for living, support, future orientation)?","yes":7,"no":4,"teach":"Protective factors lower acuity but never cancel a plan with means. Weigh them, do not over-rely on them."},{"id":7,"outcome":"MODERATE RISK","color":"#F59E0B","action":"Collaboratively build a safety plan, increase session frequency, provide crisis resources, and consider a medication/psychiatric consultation.","clinicalNote":"Ideation with intent but no plan/means, buffered by protective factors. Manage actively in the least restrictive setting that keeps the client safe."},{"id":8,"question":"Is there a history of previous attempts?","yes":6,"no":9,"teach":"A prior attempt is among the strongest predictors of future risk even when current ideation is denied."},{"id":9,"outcome":"LOWER RISK","color":"#10B981","action":"Continue monitoring, document the assessment clearly, and re-screen at each session.","clinicalNote":"No current ideation and no attempt history — but document the negative screen. Risk is dynamic and is reassessed every session."}]},"levelOfCare":{"id":"levelOfCare","title":"Level of Care Selection","category":"safety","domain":"Treatment Planning","description":"Triage to the least restrictive setting that can keep the client safe and meet clinical need.","whatToNotice":"Two axes: (1) safety — can the client stay safe in the community? and (2) intensity — how much structure do symptoms require? Safety is gated first; intensity tunes the rest.","whyItMatters":"The NCMHCE frequently tests \"least restrictive environment.\" Recommending a higher level than indicated is disruptive and scored as an error; recommending too low when safety is at stake is worse.","goldenFormula":"Validate the difficulty the client is in, explore safety and functional impairment, then act by matching the setting — stepping up or down as the picture changes.","startId":1,"nodes":[{"id":1,"question":"Can the client maintain safety in the community (no active SI/HI with intent or plan, no acute psychosis, medically stable)?","yes":3,"no":2,"teach":"Safety is the gate. If the answer is no, level of care is decided before intensity is even considered."},{"id":2,"outcome":"INPATIENT / CRISIS STABILIZATION","color":"#EF4444","action":"24/7 supervision to secure immediate safety; medically supervised withdrawal if substance-related; stabilize, then step down.","clinicalNote":"Reserved for acute danger or medical instability. Most restrictive — used only when nothing less can keep the client safe."},{"id":3,"question":"Can the client stay safe overnight but need daily structured treatment (about 6+ hours/day)?","yes":4,"no":5,"teach":"PHP is the step-down from inpatient or step-up from IOP for severe symptoms that do not require overnight supervision."},{"id":4,"outcome":"PARTIAL HOSPITALIZATION (PHP)","color":"#F59E0B","action":"Day treatment ~5 days/week, 6+ hours/day. Strong fit for recent inpatient discharge or severe symptoms with overnight safety.","clinicalNote":"Bridges inpatient and outpatient. Client sleeps at home but spends most of the day in structured care."},{"id":5,"question":"Do symptoms need more than weekly contact, while the client still functions at home and work?","yes":6,"no":7,"teach":"IOP adds group + individual structure several days a week without removing the client from daily life."},{"id":6,"outcome":"INTENSIVE OUTPATIENT (IOP)","color":"#3B82F6","action":"3–5 days/week, 3–4 hours/day. Group plus individual; well-suited to early SUD recovery and co-occurring disorders.","clinicalNote":"More structure than weekly therapy, less than PHP. Common step-down or response to insufficient outpatient progress."},{"id":7,"outcome":"OUTPATIENT (OP)","color":"#10B981","action":"Weekly or less. Mild-to-moderate symptoms, adequate functioning, and a supportive environment.","clinicalNote":"The default least-restrictive setting. Start here unless symptoms or safety call for more."}]},"mood":{"id":"mood","title":"Depression vs. Bipolar Differential","category":"differential","domain":"Assessment & Diagnosis","description":"Distinguishing unipolar depression from the bipolar spectrum before settling on a treatment plan.","whatToNotice":"The presenting episode is almost always depressive — the differential lives in the lifetime history. Always screen for past mania or hypomania before treating depression.","whyItMatters":"Antidepressant monotherapy in an undetected bipolar client can trigger a manic switch or rapid cycling. Missing a prior manic episode is one of the most consequential diagnostic errors the exam probes.","goldenFormula":"Validate the current low mood, explore the full lifetime mood history (mania, hypomania, family history, duration), then act on the diagnosis the history supports — not just the snapshot in the room.","startId":1,"nodes":[{"id":1,"question":"Is a current depressive episode present?","yes":2,"no":10,"teach":"Confirm the current episode first, then mine the history. The snapshot rarely settles the diagnosis on its own."},{"id":2,"question":"Any history of a manic episode (1+ week of elevated mood, decreased need for sleep, grandiosity)?","yes":3,"no":4,"teach":"A single lifetime manic episode establishes Bipolar I — even if the client presents depressed today."},{"id":3,"outcome":"BIPOLAR I","color":"#8B5CF6","action":"Mood stabilizer is primary; avoid antidepressant monotherapy; monitor closely for cycling.","clinicalNote":"One manic episode is sufficient — depression is not even required for the diagnosis."},{"id":4,"question":"Any history of a hypomanic episode (4+ days, less severe, no hospitalization)?","yes":5,"no":6,"teach":"Hypomania is shorter and milder than mania and does not cause marked impairment or hospitalization."},{"id":5,"outcome":"BIPOLAR II","color":"#6366F1","action":"Mood stabilizer or atypical antipsychotic; use antidepressants cautiously and rarely alone.","clinicalNote":"Requires at least one hypomanic and one major depressive episode, with no full manic episode."},{"id":6,"question":"Family history of bipolar disorder?","yes":7,"no":8,"teach":"A bipolar family history raises the index of suspicion and the caution around antidepressants."},{"id":7,"outcome":"MDD (monitor for bipolar)","color":"#F59E0B","action":"Treat MDD, but monitor closely for emerging manic/hypomanic symptoms — especially after starting an antidepressant.","clinicalNote":"No mood elevation yet, but family history warrants vigilance for a later switch."},{"id":8,"question":"Has the depression lasted 2+ years (more days than not)?","yes":9,"no":11,"teach":"Chronic, lower-grade depression over years points toward persistent depressive disorder."},{"id":9,"outcome":"PERSISTENT DEPRESSIVE DISORDER","color":"#3B82F6","action":"Plan for long-term treatment; combined therapy plus medication is often needed.","clinicalNote":"Chronicity (2+ years) is the defining feature, even when symptoms are milder than a major episode."},{"id":10,"outcome":"EVALUATE OTHER CONDITIONS","color":"#6B7280","action":"Assess for anxiety, adjustment disorder, grief, or a medical/substance cause before assigning a mood diagnosis.","clinicalNote":"No clear current depressive episode — widen the differential rather than forcing a mood label."},{"id":11,"outcome":"MAJOR DEPRESSIVE DISORDER","color":"#3B82F6","action":"CBT and/or an antidepressant; severity and safety guide the level of care.","clinicalNote":"Unipolar episode with no bipolar history and under 2 years — the most common endpoint, reached only after ruling out mania/hypomania."}]},"trauma":{"id":"trauma","title":"Trauma & Stressor Differential","category":"differential","domain":"Assessment & Diagnosis","description":"Sorting acute stress disorder, PTSD, and adjustment disorder by trauma type and timeline.","whatToNotice":"Two hinges decide everything: did the event meet Criterion A (actual/threatened death, serious injury, or sexual violence)? and how much time has passed (the 3-day / 1-month / 3-month windows)?","whyItMatters":"These three diagnoses share symptoms but differ in timeline and treatment urgency. Calling ASD \"PTSD\" too early, or treating a Criterion-A trauma as a mere adjustment issue, both misdirect care — and the exam tests the boundaries precisely.","goldenFormula":"Validate the impact of what happened, explore the event type and timeline carefully, then act on the diagnosis the timeline supports — early trauma-focused intervention can prevent ASD from progressing to PTSD.","startId":1,"nodes":[{"id":1,"question":"Was there exposure to actual or threatened death, serious injury, or sexual violence (DSM-5 Criterion A)?","yes":2,"no":7,"teach":"Criterion A is the gate for ASD and PTSD. Distressing-but-non-Criterion-A events route toward adjustment disorder."},{"id":2,"question":"Has MORE than one month passed since the event?","yes":3,"no":5,"teach":"The 1-month line separates the ASD window (under 1 month) from PTSD (1 month or more)."},{"id":3,"question":"Do intrusion, avoidance, negative mood/cognition, AND arousal symptoms persist with impairment?","yes":4,"no":6,"teach":"PTSD requires the full symptom-cluster picture persisting beyond a month."},{"id":4,"outcome":"PTSD","color":"#8B5CF6","action":"Trauma-focused therapy (CPT, PE, or EMDR). Establish safety and coping before processing the trauma directly.","clinicalNote":"Criterion-A event, 1+ month, full clusters. Stabilization precedes trauma processing — never flood early."},{"id":5,"question":"Are characteristic symptoms (intrusion, dissociation, avoidance, arousal) present from 3 days up to 1 month?","yes":8,"no":6,"teach":"ASD lives in the 3-day-to-1-month window and prominently features dissociation."},{"id":6,"outcome":"ADJUSTMENT DISORDER / SUBCLINICAL","color":"#3B82F6","action":"Supportive counseling, problem-solving, and monitoring; reassess if symptoms intensify or cross a diagnostic threshold.","clinicalNote":"Symptoms present but below the ASD/PTSD threshold or timeline — manage supportively and watch the trajectory."},{"id":7,"question":"Are emotional/behavioral symptoms occurring within 3 months of an identifiable stressor (no Criterion-A event)?","yes":6,"no":9,"teach":"Adjustment disorder follows an identifiable stressor that does not meet the trauma threshold."},{"id":8,"outcome":"ACUTE STRESS DISORDER","color":"#F59E0B","action":"Brief trauma-focused CBT, psychoeducation, and stabilization. Monitor for progression — early intervention reduces the move to PTSD.","clinicalNote":"Criterion-A event within the past month. Avoid single-session psychological debriefing, which is unsupported and may harm."},{"id":9,"outcome":"EVALUATE OTHER CONDITIONS","color":"#6B7280","action":"Clarify the timeline and stressor; assess for mood, anxiety, or other disorders before concluding.","clinicalNote":"No qualifying event and no clear stressor link — broaden the assessment."}]},"anxiety":{"id":"anxiety","title":"Anxiety Disorder Differential","category":"differential","domain":"Assessment & Diagnosis","description":"Distinguishing the major anxiety disorders by what the fear is about and how it is triggered.","whatToNotice":"The content and cue of the fear are diagnostic: a specific object, social scrutiny, unexpected panic surges, or pervasive multi-domain worry each point to a different disorder.","whyItMatters":"Treatment diverges sharply — graduated exposure for phobias, interoceptive exposure for panic, worry-focused CBT for GAD. Naming the anxiety correctly determines which evidence-based protocol applies.","goldenFormula":"Validate the anxiety as real and impairing, explore exactly what the fear is about and how it is cued, then act with the exposure-based protocol matched to that disorder.","startId":1,"nodes":[{"id":1,"question":"Is the fear cued by a specific object or situation?","yes":2,"no":5,"teach":"A discrete, predictable trigger points toward a phobic or social presentation rather than free-floating worry."},{"id":2,"question":"Is the feared situation social, involving possible scrutiny or judgment?","yes":3,"no":4,"teach":"Social anxiety centers on evaluation; specific phobia centers on the object/situation itself."},{"id":3,"outcome":"SOCIAL ANXIETY DISORDER","color":"#6366F1","action":"CBT with exposure plus cognitive restructuring around evaluation and judgment fears.","clinicalNote":"Fear of negative evaluation across social/performance situations is the hallmark."},{"id":4,"outcome":"SPECIFIC PHOBIA","color":"#3B82F6","action":"Graduated in-vivo exposure is first-line and often produces rapid improvement; medication has a limited role.","clinicalNote":"Marked, out-of-proportion fear of a specific object/situation, with avoidance lasting 6+ months."},{"id":5,"question":"Are there recurrent UNEXPECTED panic attacks with persistent worry about future attacks?","yes":6,"no":7,"teach":"Panic disorder features uncued, out-of-the-blue surges plus anticipatory worry about the next one."},{"id":6,"outcome":"PANIC DISORDER","color":"#8B5CF6","action":"CBT with interoceptive exposure and psychoeducation about the panic cycle and bodily sensations.","clinicalNote":"Unexpected attacks distinguish this from cued anxiety; the worry about attacks sustains the disorder."},{"id":7,"question":"Is there excessive, hard-to-control worry across multiple life domains for 6+ months?","yes":8,"no":9,"teach":"GAD is defined by pervasive, diffuse worry rather than a single feared cue."},{"id":8,"outcome":"GENERALIZED ANXIETY DISORDER","color":"#10B981","action":"CBT (worry exposure, cognitive work, relaxation); consider an SSRI consultation for moderate-to-severe cases.","clinicalNote":"Multi-domain, chronic worry with physical symptoms (tension, fatigue, sleep) for 6+ months."},{"id":9,"outcome":"EVALUATE FURTHER","color":"#6B7280","action":"Assess for separation anxiety, OCD, trauma-related disorders, or a medical/substance cause.","clinicalNote":"The pattern fits none of the above cleanly — widen the differential before labeling."}]},"ethics":{"id":"ethics","title":"Confidentiality & Duty to Warn","category":"ethics","domain":"Professional Practice & Ethics","description":"Working through the limits of confidentiality when safety, mandated reporting, or the courts are involved.","whatToNotice":"Three distinct triggers can pierce confidentiality: a specific threat to an identifiable person, suspected abuse of a protected class, and a valid court order. Each has its own pathway — do not blur them.","whyItMatters":"Both over-disclosing and failing to act create ethical and legal exposure. The exam tests whether you release the minimum necessary, follow the correct pathway, and document — not whether you \"report everything\" or \"protect confidentiality at all costs.\"","goldenFormula":"Validate the client and the limits of confidentiality (ideally disclosed up front), explore the specifics of the threat or request, then act with the narrowest legally and ethically required response — and document it.","startId":1,"nodes":[{"id":1,"question":"Has the client disclosed intent to harm an identifiable person?","yes":2,"no":6,"teach":"Duty-to-warn analysis begins only when a threat targets an identifiable victim, not for vague anger."},{"id":2,"question":"Is the threat specific and imminent?","yes":3,"no":4,"teach":"Specificity and imminence elevate a statement into a duty-to-protect situation."},{"id":3,"question":"Can you identify the potential victim?","yes":5,"no":4,"teach":"An identifiable victim is what makes warning possible and, in many states, required."},{"id":4,"outcome":"DOCUMENT & MONITOR","color":"#F59E0B","action":"Document thoroughly, increase monitoring, explore the thoughts further, and consult as needed.","clinicalNote":"Threat is non-specific or no victim is identifiable — manage clinically and document, but the warning duty is not yet triggered."},{"id":5,"outcome":"DUTY TO WARN / PROTECT","color":"#EF4444","action":"Warn the identifiable victim and/or notify law enforcement per your state statute; document every action taken.","clinicalNote":"Specific, imminent threat to an identifiable person. Follow your jurisdiction’s Tarasoff-derived statute precisely."},{"id":6,"question":"Is there suspected child, elder, or dependent-adult abuse?","yes":7,"no":8,"teach":"Mandated reporting is a separate pathway from duty to warn and is triggered by reasonable suspicion."},{"id":7,"outcome":"MANDATED REPORT","color":"#EF4444","action":"File the mandatory report per state law, document it, and inform the client of the limits of confidentiality.","clinicalNote":"Reasonable suspicion — not proof — triggers the duty. The threshold is intentionally low."},{"id":8,"question":"Is there a valid court order for the records?","yes":9,"no":10,"teach":"A subpoena is not the same as a court order; verify validity and consult before releasing anything."},{"id":9,"outcome":"RELEASE REQUIRED INFO","color":"#F59E0B","action":"Release only what is legally required, consult an attorney if needed, and document the disclosure.","clinicalNote":"Minimum-necessary standard applies even under a court order — never release the whole file by default."},{"id":10,"outcome":"MAINTAIN CONFIDENTIALITY","color":"#10B981","action":"Standard confidentiality applies; do not release without written client consent.","clinicalNote":"No threat, no mandated-report trigger, no valid order — confidentiality holds."}]},"homicidal":{"id":"homicidal","title":"Homicidal Ideation / Threat Assessment","category":"safety","domain":"Risk & Safety","description":"Evaluating threats of harm to others and determining the appropriate clinical and legal response.","whatToNotice":"Specificity of target, imminence, plan, means access, and history of violence. A vague statement of anger is not the same as a named target with a plan.","whyItMatters":"The NCMHCE tests the boundary between clinical management (document and monitor) and legal duty (warn/protect). Acting too early breaches confidentiality unnecessarily; acting too late endangers lives.","goldenFormula":"Validate the feelings behind the anger, explore the specifics (who, when, how, access to means), then act at the level the threat warrants — document, warn, or hospitalize.","startId":1,"nodes":[{"id":1,"question":"Has the client expressed intent to harm a specific person?","yes":2,"no":7,"teach":"Vague anger (\"I could kill someone\") is clinically different from a named target with intent."},{"id":2,"question":"Is the threat specific and imminent?","yes":3,"no":6,"teach":"Imminence means the person intends to act in the near future — not a hypothetical."},{"id":3,"question":"Does the client have a plan and access to means?","yes":4,"no":5,"teach":"Plan + means access is the highest-risk combination, paralleling suicide assessment."},{"id":4,"outcome":"DUTY TO WARN/PROTECT","color":"#EF4444","action":"Warn identifiable victim(s), notify law enforcement per state statute, consider hospitalization, document all actions.","clinicalNote":"Specific, imminent threat with plan and means to an identifiable victim. Follow your state Tarasoff statute precisely."},{"id":5,"outcome":"HIGH CONCERN — MANAGE ACTIVELY","color":"#F59E0B","action":"Increase session frequency, develop a de-escalation plan, restrict means if possible, consult, document thoroughly.","clinicalNote":"Intent present but plan or means incomplete. Clinical management with heightened monitoring."},{"id":6,"outcome":"DOCUMENT & MONITOR","color":"#F59E0B","action":"Document the statements verbatim, explore the context, develop coping strategies, reassess each session.","clinicalNote":"Non-imminent threat. Clinical management is appropriate; duty to warn not triggered."},{"id":7,"question":"Is there a history of violent behavior?","yes":8,"no":9,"teach":"Past violence is among the strongest predictors of future violence, even without current threats."},{"id":8,"outcome":"ELEVATED BASELINE RISK","color":"#F59E0B","action":"Assess current stressors and triggers, evaluate substance use, increase structure, consider violence risk tool (HCR-20).","clinicalNote":"No current threat but historical risk factors. Proactive risk management and documentation."},{"id":9,"outcome":"STANDARD MONITORING","color":"#10B981","action":"Continue routine assessment, document negative screen, reassess if circumstances change.","clinicalNote":"No current threat and no violence history. Document the assessment and revisit as needed."}]},"mandatedReport":{"id":"mandatedReport","title":"Mandated Reporting Decision","category":"safety","domain":"Ethics & Legal","description":"Determining when and how to file a mandated report of suspected abuse or neglect.","whatToNotice":"The threshold is reasonable suspicion — not proof. Physical indicators, behavioral changes, disclosures (direct or indirect), and caregiver behavior patterns.","whyItMatters":"Failure to report is both an ethical violation and a criminal offense in most states. Over-reporting (without reasonable basis) can damage the therapeutic alliance. The exam tests whether you know the threshold and the process.","goldenFormula":"Validate the client/child, explore what you are observing (without conducting your own investigation), then act by filing the report per your state law and documenting.","startId":1,"nodes":[{"id":1,"question":"Is there reasonable suspicion of abuse or neglect of a child, elder, or dependent adult?","yes":2,"no":6,"teach":"Reasonable suspicion — not certainty. You are not the investigator; CPS/APS determines whether abuse occurred."},{"id":2,"question":"Is the suspected victim a minor (under 18)?","yes":3,"no":4,"teach":"Child abuse reporting laws are universal across states. Elder/dependent adult laws vary more."},{"id":3,"outcome":"FILE CHILD ABUSE REPORT","color":"#EF4444","action":"Report to your state child protective services hotline immediately. Document what you observed/heard, when you reported, and to whom.","clinicalNote":"All 50 states require counselors to report suspected child abuse. You do not need proof — reasonable suspicion is the legal threshold."},{"id":4,"question":"Does your state mandate reporting for this population (elder, dependent adult)?","yes":5,"no":7,"teach":"Elder/dependent adult reporting laws vary by state. Know your jurisdiction requirements."},{"id":5,"outcome":"FILE ADULT PROTECTIVE REPORT","color":"#EF4444","action":"Report to Adult Protective Services. Document observations, report details, and rationale.","clinicalNote":"Most states mandate reporting suspected abuse of vulnerable adults. Check your state statute for specific populations covered."},{"id":6,"question":"Are there concerning indicators that do not yet reach reasonable suspicion?","yes":8,"no":9,"teach":"Some situations warrant increased vigilance without yet triggering the reporting duty."},{"id":7,"outcome":"DOCUMENT CONCERNS","color":"#F59E0B","action":"Document your observations carefully. Continue monitoring. Consult with a supervisor or ethics board if uncertain.","clinicalNote":"Not a mandated report situation in your jurisdiction, but document concerns and reassess."},{"id":8,"outcome":"HEIGHTENED MONITORING","color":"#F59E0B","action":"Document concerns, increase assessment focus in future sessions, consult with supervisor.","clinicalNote":"Below reporting threshold but clinically concerning. Ongoing assessment may tip into reasonable suspicion."},{"id":9,"outcome":"NO REPORTING INDICATED","color":"#10B981","action":"Continue standard care. Document the assessment.","clinicalNote":"No indicators of abuse or neglect at this time."}]},"withdrawal":{"id":"withdrawal","title":"Substance Withdrawal Emergency","category":"safety","domain":"Risk & Safety","description":"Identifying medically dangerous withdrawal syndromes that require immediate intervention.","whatToNotice":"The substance class determines the danger level. Alcohol and benzodiazepine withdrawal can be fatal (seizures, delirium tremens). Opioid withdrawal is miserable but rarely lethal. Stimulant withdrawal is mostly psychological.","whyItMatters":"The NCMHCE tests whether you recognize which withdrawals are medical emergencies versus which can be managed outpatient. Sending an alcohol-dependent client home to \"tough it out\" can kill them.","goldenFormula":"Validate the distress, explore the substance history (what, how much, how long, last use), then act with the appropriate medical referral based on the risk level.","startId":1,"nodes":[{"id":1,"question":"Is the client withdrawing from alcohol or benzodiazepines?","yes":2,"no":5,"teach":"Alcohol and benzo withdrawal are the two that can produce fatal seizures and delirium tremens."},{"id":2,"question":"Has the client used heavily and daily for weeks or longer?","yes":3,"no":4,"teach":"Duration and quantity determine withdrawal severity. Brief or light use carries less risk."},{"id":3,"outcome":"MEDICAL EMERGENCY — REFER IMMEDIATELY","color":"#EF4444","action":"Refer for medically supervised detox. Use CIWA protocol for alcohol. Never advise abrupt cessation of heavy alcohol or benzo use.","clinicalNote":"Alcohol/benzo withdrawal can produce seizures within 24-72 hours. This is not manageable in outpatient counseling alone."},{"id":4,"outcome":"MEDICAL EVALUATION RECOMMENDED","color":"#F59E0B","action":"Refer for medical assessment. Lower risk but still needs professional evaluation for safe tapering.","clinicalNote":"Lighter or shorter use lowers risk but does not eliminate it. Medical guidance still appropriate."},{"id":5,"question":"Is the client withdrawing from opioids?","yes":6,"no":8,"teach":"Opioid withdrawal is extremely uncomfortable but rarely medically dangerous in otherwise healthy adults."},{"id":6,"outcome":"INITIATE MAT REFERRAL","color":"#F59E0B","action":"Refer for MAT evaluation (buprenorphine/methadone). Symptom management for comfort. Withdrawal itself is not life-threatening but drives relapse.","clinicalNote":"Opioid withdrawal is rarely fatal but the discomfort drives relapse, which carries overdose risk. MAT is the evidence-based response."},{"id":7,"outcome":"OUTPATIENT MANAGEMENT","color":"#10B981","action":"Monitor symptoms, provide psychoeducation, supportive counseling. Medical referral if symptoms escalate.","clinicalNote":"Stimulant and cannabis withdrawal are primarily psychological — fatigue, depression, irritability, cravings. Manageable outpatient."},{"id":8,"question":"Is the client withdrawing from stimulants, cannabis, or tobacco?","yes":7,"no":9,"teach":"These withdrawals are uncomfortable but not medically dangerous."},{"id":9,"outcome":"ASSESS FURTHER","color":"#6B7280","action":"Clarify the substance, timeline, and pattern of use before determining risk level.","clinicalNote":"Cannot assess withdrawal risk without knowing the substance. Gather history first."}]},"psychotic":{"id":"psychotic","title":"Psychotic Spectrum Differential","category":"differential","domain":"Assessment & Diagnosis","description":"Distinguishing schizophrenia, schizoaffective disorder, brief psychotic disorder, and psychosis from other causes.","whatToNotice":"Duration of psychosis, presence of mood episodes, and whether psychosis occurs independently of mood. Also rule out substances and medical causes first.","whyItMatters":"Treatment differs significantly — schizoaffective needs both a mood stabilizer and antipsychotic; brief psychotic disorder may resolve without long-term medication. Misdiagnosis leads to wrong treatment.","goldenFormula":"Validate the distress, explore the timeline (onset, duration, relationship to mood episodes), then act on the diagnosis the timeline supports.","startId":1,"nodes":[{"id":1,"question":"Can substance use or a medical condition account for the psychotic symptoms?","yes":2,"no":3,"teach":"Always rule out substance-induced and medical causes before diagnosing a primary psychotic disorder."},{"id":2,"outcome":"SUBSTANCE-INDUCED OR MEDICAL","color":"#F59E0B","action":"Treat the underlying cause. Monitor for persistent psychosis after substances clear (typically 1 month).","clinicalNote":"Stimulants, hallucinogens, high-dose cannabis, and medical conditions (delirium, endocrine) can all produce psychosis."},{"id":3,"question":"Have psychotic symptoms lasted 6 months or longer (including prodromal)?","yes":4,"no":7,"teach":"The 6-month duration requirement is what separates schizophrenia from shorter psychotic episodes."},{"id":4,"question":"Have major mood episodes (manic or depressive) been present for the MAJORITY of the total illness duration?","yes":5,"no":6,"teach":"This distinguishes schizoaffective from schizophrenia. Mood episodes must be present for most of the illness."},{"id":5,"outcome":"SCHIZOAFFECTIVE DISORDER","color":"#8B5CF6","action":"Antipsychotic + mood stabilizer + CBTp. Recovery-oriented psychosocial support.","clinicalNote":"Key: psychosis persists for 2+ weeks WITHOUT mood episodes, AND mood episodes are present for the majority of illness duration."},{"id":6,"outcome":"SCHIZOPHRENIA","color":"#EF4444","action":"Antipsychotic medication + CBTp + psychosocial rehabilitation + family psychoeducation.","clinicalNote":"6+ months of psychotic symptoms without major mood episodes constituting the majority of illness. Most chronic of the psychotic spectrum."},{"id":7,"question":"Have symptoms lasted between 1 and 6 months?","yes":8,"no":9,"teach":"Schizophreniform disorder occupies the 1-6 month window — essentially \"provisional schizophrenia.\""},{"id":8,"outcome":"SCHIZOPHRENIFORM DISORDER","color":"#3B82F6","action":"Antipsychotic treatment. Monitor closely — may resolve or progress to schizophrenia after 6 months.","clinicalNote":"Provisional diagnosis. One-third recover, two-thirds progress to schizophrenia. The 6-month mark is the decision point."},{"id":9,"outcome":"BRIEF PSYCHOTIC DISORDER","color":"#10B981","action":"Short-term antipsychotic. Supportive therapy. Resolves within one month by definition.","clinicalNote":"Duration <1 month with full return to functioning. Often stress-related. Best prognosis on the spectrum."}]},"adhdDiff":{"id":"adhdDiff","title":"ADHD vs Anxiety vs Depression Overlap","category":"differential","domain":"Assessment & Diagnosis","description":"Separating ADHD from anxiety and depression when concentration problems are the presenting complaint.","whatToNotice":"Onset timing is the key. ADHD is lifelong (symptoms before age 12). Anxiety/depression inattention is acquired and tied to onset of mood/anxiety symptoms.","whyItMatters":"All three cause concentration problems. Treating ADHD with stimulants when the real issue is anxiety makes anxiety worse. Treating depression inattention with stimulants misses the mood disorder.","goldenFormula":"Validate the concentration struggles, explore the developmental timeline (childhood history, onset), then act on the pattern the history reveals.","startId":1,"nodes":[{"id":1,"question":"Were attention/concentration problems present before age 12, across multiple settings (home, school)?","yes":2,"no":5,"teach":"ADHD requires childhood onset. Adult-onset concentration problems point elsewhere."},{"id":2,"question":"Are symptoms chronic and pervasive (not episodic)?","yes":3,"no":4,"teach":"ADHD is a trait, not an episode. If inattention comes and goes with mood, it is likely mood-driven."},{"id":3,"outcome":"ADHD (possible comorbidity)","color":"#3B82F6","action":"Comprehensive ADHD evaluation. Screen for comorbid anxiety/depression (very common overlap). Stimulant + behavioral strategies.","clinicalNote":"Childhood onset + pervasive + chronic = ADHD. But ADHD is frequently comorbid with anxiety and depression — assess for both."},{"id":4,"outcome":"MOOD/ANXIETY WITH ADHD-LIKE FEATURES","color":"#F59E0B","action":"Treat the mood or anxiety disorder first. Reassess concentration after mood stabilizes.","clinicalNote":"Episodic inattention that tracks with mood episodes is likely secondary to the mood disorder, not primary ADHD."},{"id":5,"question":"Did concentration problems begin alongside depressed mood, loss of interest, or sleep changes?","yes":6,"no":7,"teach":"Depression impairs concentration, memory, and processing speed — mimicking ADHD in adults."},{"id":6,"outcome":"DEPRESSION WITH COGNITIVE SYMPTOMS","color":"#8B5CF6","action":"Treat the depression (CBT + possible SSRI). Concentration typically improves as depression lifts.","clinicalNote":"Depression pseudo-ADHD. The concentration problems are symptoms of depression, not a separate disorder."},{"id":7,"question":"Is the inattention driven by worry, racing thoughts, or preoccupation with feared outcomes?","yes":8,"no":9,"teach":"Anxiety hijacks attention toward threat — it looks like distractibility but the mechanism is different."},{"id":8,"outcome":"ANXIETY-DRIVEN INATTENTION","color":"#F59E0B","action":"Treat the anxiety disorder (CBT, possibly SSRI). Attention normalizes when anxiety is managed.","clinicalNote":"Anxious inattention is preoccupation, not distractibility. The mind is focused — on the wrong thing."},{"id":9,"outcome":"FURTHER ASSESSMENT NEEDED","color":"#6B7280","action":"Comprehensive neuropsychological or psychoeducational evaluation. Collateral history from family/teachers.","clinicalNote":"Pattern does not clearly fit one pathway. Formal testing can differentiate."}]},"bpdDiff":{"id":"bpdDiff","title":"BPD vs Complex Trauma vs Bipolar","category":"differential","domain":"Assessment & Diagnosis","description":"Differentiating borderline personality disorder, complex PTSD, and bipolar disorder when mood instability is the primary presentation.","whatToNotice":"Speed of mood shifts, triggers, and interpersonal patterns. BPD shifts in hours (interpersonal trigger). Bipolar shifts in days-weeks (endogenous). Complex trauma has dissociation and relational disruption with a trauma history.","whyItMatters":"BPD gets DBT. Bipolar gets mood stabilizers. Complex trauma gets phase-oriented trauma therapy. Wrong diagnosis means wrong treatment — and potentially harmful treatment (e.g., antidepressant monotherapy in bipolar).","goldenFormula":"Validate the emotional pain, explore the pattern (triggers, duration, trauma history, interpersonal dynamics), then act on the best-fit diagnosis.","startId":1,"nodes":[{"id":1,"question":"Do mood shifts happen within hours and are typically triggered by interpersonal events (rejection, abandonment, conflict)?","yes":2,"no":4,"teach":"Rapid, interpersonally triggered shifts are the hallmark of BPD emotional dysregulation."},{"id":2,"question":"Is there a pervasive pattern of unstable relationships, identity disturbance, impulsivity, and frantic efforts to avoid abandonment?","yes":3,"no":4,"teach":"BPD requires a pervasive pattern across multiple criteria — not just mood instability alone."},{"id":3,"outcome":"BORDERLINE PERSONALITY DISORDER","color":"#EF4444","action":"DBT as primary treatment. Address suicidality and self-harm with a structured safety protocol.","clinicalNote":"Mood shifts in hours, interpersonal triggers, identity disturbance, abandonment fears, impulsivity. DBT has the strongest evidence."},{"id":4,"question":"Do mood episodes last days to weeks with distinct periods of elevated/irritable mood, decreased sleep need, and grandiosity?","yes":5,"no":6,"teach":"Bipolar episodes have a distinct beginning and end, last days-weeks, and often include sleep reduction without fatigue."},{"id":5,"outcome":"BIPOLAR DISORDER","color":"#8B5CF6","action":"Mood stabilizer is primary. Avoid antidepressant monotherapy. Add therapy after stabilization.","clinicalNote":"Episode duration (days-weeks), endogenous onset, decreased sleep need, and grandiosity distinguish bipolar from BPD."},{"id":6,"question":"Is there a significant trauma history with dissociation, relational disruption, and negative self-concept beyond PTSD criteria?","yes":7,"no":8,"teach":"Complex PTSD adds identity disturbance, relational problems, and affect dysregulation to the standard PTSD symptom set."},{"id":7,"outcome":"COMPLEX PTSD / TRAUMA-RELATED","color":"#F59E0B","action":"Phase-oriented trauma therapy. Stabilization before processing. Address dissociation and relational patterns.","clinicalNote":"Trauma history + dissociation + relational disruption + negative self-concept. Overlaps significantly with BPD — some clients meet criteria for both."},{"id":8,"outcome":"FURTHER DIFFERENTIATION NEEDED","color":"#6B7280","action":"Comprehensive assessment with timeline, collateral history, and structured diagnostic interview.","clinicalNote":"Mood instability that does not clearly fit one pattern. Consider comorbidity — BPD and Bipolar can co-occur."}]},"ocdSpectrum":{"id":"ocdSpectrum","title":"OCD Spectrum Differential","category":"differential","domain":"Assessment & Diagnosis","description":"Distinguishing OCD from GAD, hoarding disorder, body dysmorphic disorder, and OCPD.","whatToNotice":"Ego-dystonic vs ego-syntonic. OCD thoughts are unwanted and distressing (ego-dystonic). OCPD rigidity is valued (ego-syntonic). GAD worry is realistic and diffuse. BDD focuses on perceived appearance flaws.","whyItMatters":"ERP is the gold standard for OCD but would not be first-line for GAD or OCPD. Hoarding has its own specialized CBT. Misclassifying wastes treatment time.","goldenFormula":"Validate the distress, explore the content (obsessions? appearance? possessions? diffuse worry?) and the relationship to it (unwanted or valued?), then act with the matched treatment.","startId":1,"nodes":[{"id":1,"question":"Are there intrusive, unwanted, ego-dystonic thoughts that cause marked anxiety?","yes":2,"no":5,"teach":"The ego-dystonic nature of OCD obsessions is the key differentiator. The person does NOT want these thoughts."},{"id":2,"question":"Are there repetitive behaviors or mental acts performed to reduce the anxiety from the obsessions?","yes":3,"no":4,"teach":"Compulsions are the behavioral response to obsessions. They can be overt (handwashing) or covert (mental reviewing)."},{"id":3,"outcome":"OBSESSIVE-COMPULSIVE DISORDER","color":"#8B5CF6","action":"ERP (Exposure and Response Prevention) as first-line. SSRI augmentation for moderate-severe cases.","clinicalNote":"Ego-dystonic obsessions + compulsions = OCD. ERP is the most effective treatment — more effective than medication alone."},{"id":4,"outcome":"OBSESSIVE FEATURES WITHOUT OCD","color":"#3B82F6","action":"Assess for anxiety disorders, depression with rumination, or obsessive personality traits. Treat the underlying condition.","clinicalNote":"Intrusive thoughts without compulsions may be anxiety, depression, or a different OCD-related condition."},{"id":5,"question":"Is the primary concern about perceived flaws in physical appearance that others do not see?","yes":6,"no":7,"teach":"BDD involves preoccupation with perceived defects that are not observable or appear slight to others."},{"id":6,"outcome":"BODY DYSMORPHIC DISORDER","color":"#F59E0B","action":"CBT-BDD + SSRI. Do NOT refer for cosmetic procedures — they do not resolve BDD and often worsen it.","clinicalNote":"BDD is OCD-related but appearance-focused. Mirror checking and reassurance-seeking are common compulsive behaviors."},{"id":7,"question":"Is there persistent difficulty discarding possessions with emotional attachment to objects?","yes":8,"no":9,"teach":"Hoarding disorder is now separate from OCD in the DSM-5. The attachment to objects is the core feature, not contamination or symmetry obsessions."},{"id":8,"outcome":"HOARDING DISORDER","color":"#F59E0B","action":"Specialized CBT for hoarding (sorting, decision-making training). Forced cleanouts backfire.","clinicalNote":"Hoarding is separate from OCD. The items carry emotional significance — treatment targets the beliefs about possessions."},{"id":9,"question":"Is the pattern one of rigid perfectionism, orderliness, and control that the person values and defends?","yes":10,"no":11,"teach":"OCPD rigidity is ego-syntonic — the person believes their standards are correct. This is the opposite of OCD."},{"id":10,"outcome":"OBSESSIVE-COMPULSIVE PERSONALITY DISORDER","color":"#3B82F6","action":"CBT targeting rigidity and interpersonal impact. Psychodynamic exploration of control needs.","clinicalNote":"Ego-syntonic is the differentiator. The OCPD client does not see the problem — others around them do."},{"id":11,"outcome":"GENERALIZED ANXIETY DISORDER","color":"#10B981","action":"CBT with worry exposure and relaxation. SSRI for moderate-severe.","clinicalNote":"GAD worry is realistic but excessive, across multiple domains, without the obsession-compulsion cycle of OCD."}]},"eating":{"id":"eating","title":"Eating Disorder Differential","category":"differential","domain":"Assessment & Diagnosis","description":"Distinguishing anorexia nervosa, bulimia nervosa, binge-eating disorder, and ARFID.","whatToNotice":"Body weight status, body image distortion, and the presence or absence of binge and compensatory behaviors. ARFID has no body image concern.","whyItMatters":"Medical risk differs dramatically — anorexia has the highest mortality of any psychiatric disorder. Level of care decisions depend on the specific diagnosis and medical status.","goldenFormula":"Validate the suffering, explore eating patterns and body image beliefs, then act with the appropriate level of care and evidence-based treatment.","startId":1,"nodes":[{"id":1,"question":"Is body weight significantly low for age, sex, and development?","yes":2,"no":4,"teach":"Significantly low weight is the defining feature of anorexia nervosa — not present in bulimia or BED."},{"id":2,"question":"Is the restriction driven by body image distortion or intense fear of weight gain?","yes":3,"no":7,"teach":"Body image distortion separates anorexia from ARFID and medical causes of low weight."},{"id":3,"outcome":"ANOREXIA NERVOSA","color":"#EF4444","action":"Medical monitoring (vital signs, labs). FBT for adolescents, CBT-E for adults. Nutritional rehabilitation. Assess for hospitalization if medically unstable.","clinicalNote":"Highest mortality rate of any psychiatric disorder. Medical stability is assessed before psychological treatment begins."},{"id":4,"question":"Are there recurrent binge-eating episodes (eating large amounts with loss of control)?","yes":5,"no":7,"teach":"Binge episodes are present in both bulimia and BED. The difference is compensatory behaviors."},{"id":5,"question":"Are there compensatory behaviors after binges (purging, fasting, excessive exercise)?","yes":6,"no":8,"teach":"Compensatory behaviors define bulimia. BED has binges without purging."},{"id":6,"outcome":"BULIMIA NERVOSA","color":"#F59E0B","action":"CBT-E as first-line. SSRI (fluoxetine) is FDA-approved. Monitor for medical complications (dental, electrolyte).","clinicalNote":"Binge-purge cycle at normal or above weight. Medical monitoring for electrolyte imbalance and dental erosion."},{"id":7,"question":"Is there food avoidance or restriction NOT related to body image (sensory issues, fear of choking, lack of interest)?","yes":9,"no":10,"teach":"ARFID involves restrictive eating without the body image component of anorexia."},{"id":8,"outcome":"BINGE-EATING DISORDER","color":"#3B82F6","action":"CBT-E or IPT. Lisdexamfetamine for severe cases. Address shame and emotional eating patterns.","clinicalNote":"Recurrent binges without purging. Often associated with overweight/obesity but the diagnosis is about the binge pattern, not weight."},{"id":9,"outcome":"AVOIDANT/RESTRICTIVE FOOD INTAKE DISORDER","color":"#F59E0B","action":"Gradual food exposure therapy. Family-based intervention for children. Nutritional supplementation.","clinicalNote":"No body image distortion — restriction is driven by sensory sensitivity, fear of aversive consequences, or lack of interest in eating."},{"id":10,"outcome":"ASSESS FURTHER","color":"#6B7280","action":"Rule out medical causes, depression-related appetite changes, and cultural factors.","clinicalNote":"Eating disturbance that does not fit a specific disorder pattern. Comprehensive evaluation needed."}]},"childBehavior":{"id":"childBehavior","title":"Child Behavior Disorder Differential","category":"differential","domain":"Assessment & Diagnosis","description":"Distinguishing ODD, conduct disorder, ADHD behavioral symptoms, and trauma-driven behavior in children and adolescents.","whatToNotice":"Severity, intent, and context. ODD is defiance. CD adds aggression, destruction, and deceit. ADHD behavior is impulsive, not intentional. Trauma behavior has a trigger history.","whyItMatters":"Treatment differs — ODD responds to parent management training, CD needs MST/FFT, ADHD needs behavioral + medication, and trauma needs trauma-focused therapy. Grouping antisocial youth together worsens outcomes.","goldenFormula":"Validate the family distress, explore the pattern (intentional vs impulsive, severity, onset, trauma history), then act with the matched intervention.","startId":1,"nodes":[{"id":1,"question":"Are there serious violations: aggression to people/animals, property destruction, deceitfulness, or rule violations (theft, truancy, running away)?","yes":2,"no":4,"teach":"These serious behaviors are the hallmark of conduct disorder — beyond simple defiance."},{"id":2,"question":"Did the behavior pattern begin before age 10?","yes":3,"no":10,"teach":"Childhood-onset CD has worse prognosis and higher risk of antisocial personality disorder in adulthood."},{"id":3,"outcome":"CONDUCT DISORDER — CHILDHOOD ONSET","color":"#EF4444","action":"MST or FFT. Avoid boot camps and grouping with antisocial peers. Address family factors.","clinicalNote":"Worst prognosis. Callous-unemotional traits should be assessed as a specifier (\"with limited prosocial emotions\")."},{"id":4,"question":"Is there a pattern of angry/irritable mood, argumentative/defiant behavior, or vindictiveness — but WITHOUT the serious violations of CD?","yes":5,"no":6,"teach":"ODD is defiance without the aggression, destruction, and deceit of CD."},{"id":5,"outcome":"OPPOSITIONAL DEFIANT DISORDER","color":"#F59E0B","action":"Parent Management Training (PMT) + child-focused CBT. Address family interaction patterns.","clinicalNote":"Defiance and irritability without CD-level severity. Better prognosis. Parent training is the primary intervention."},{"id":6,"question":"Are the behavioral problems primarily impulsive (acting without thinking) rather than intentional/planned?","yes":7,"no":8,"teach":"ADHD impulsivity looks defiant but is not intentional — the child acts before considering consequences."},{"id":7,"outcome":"ADHD BEHAVIORAL PRESENTATION","color":"#3B82F6","action":"Stimulant medication + behavioral strategies + school accommodations. Parent education on impulsivity vs defiance.","clinicalNote":"Impulsive, not intentional. The child often feels bad afterward. Behavioral management must account for executive function deficits."},{"id":8,"question":"Is there a known trauma history, and did behavioral changes follow the traumatic event(s)?","yes":9,"no":11,"teach":"Trauma can present as behavioral problems — hyperarousal looks like ADHD, avoidance looks like defiance, aggression may be reactive."},{"id":9,"outcome":"TRAUMA-DRIVEN BEHAVIORAL SYMPTOMS","color":"#8B5CF6","action":"Trauma-focused CBT (TF-CBT). Stabilization before processing. Do not label trauma reactions as conduct problems.","clinicalNote":"Behavior is a trauma response, not a conduct disorder. Punitive approaches worsen trauma reactions."},{"id":10,"outcome":"CONDUCT DISORDER — ADOLESCENT ONSET","color":"#F59E0B","action":"MST or FFT. Better prognosis than childhood-onset. Peer group intervention critical.","clinicalNote":"Onset after age 10. Less likely to develop ASPD. Treatment targeting peer associations and family supervision."},{"id":11,"outcome":"FURTHER ASSESSMENT","color":"#6B7280","action":"Comprehensive evaluation including developmental history, school observations, family assessment, and screening for co-occurring conditions.","clinicalNote":"Pattern does not clearly fit one diagnosis. Comorbidity is common — ADHD + ODD is one of the most frequent combinations."}]},"neurocognitive":{"id":"neurocognitive","title":"Neurocognitive Differential","category":"differential","domain":"Assessment & Diagnosis","description":"Distinguishing delirium, dementia, and depression-related cognitive decline (pseudodementia).","whatToNotice":"Onset speed, level of consciousness, and fluctuation. Delirium is acute and fluctuating. Dementia is gradual and progressive. Pseudodementia tracks with mood onset.","whyItMatters":"Delirium is a medical emergency. Dementia requires long-term planning. Pseudodementia is treatable and reversible. Confusing them leads to either dangerous delay or unnecessary despair.","goldenFormula":"Validate the cognitive concerns, explore the timeline (acute vs gradual, consciousness changes, mood symptoms), then act with the correct urgency level.","startId":1,"nodes":[{"id":1,"question":"Did cognitive changes develop acutely (hours to days) with fluctuating consciousness or attention?","yes":2,"no":3,"teach":"Acute onset with fluctuating awareness is the hallmark of delirium — a medical emergency."},{"id":2,"outcome":"DELIRIUM — MEDICAL EMERGENCY","color":"#EF4444","action":"Immediate medical referral. Identify and treat the underlying cause (infection, medication, metabolic). Do NOT treat psychiatrically first.","clinicalNote":"Delirium is a medical condition, not a psychiatric one. Causes include UTI in elderly, medication interactions, post-surgical, substance intoxication/withdrawal."},{"id":3,"question":"Did cognitive decline develop gradually over months to years with progressive worsening?","yes":4,"no":6,"teach":"Gradual, progressive decline without fluctuating consciousness points toward a neurocognitive disorder (dementia)."},{"id":4,"question":"Are memory problems the most prominent early symptom?","yes":5,"no":8,"teach":"Early memory loss (especially recent memory) is characteristic of Alzheimer disease specifically."},{"id":5,"outcome":"MAJOR NCD DUE TO ALZHEIMER DISEASE","color":"#8B5CF6","action":"Cholinesterase inhibitors. Caregiver support and education. Safety planning. Legal/financial planning while capacity remains.","clinicalNote":"Gradual onset, progressive memory loss, language decline. Most common cause of dementia. Counselor role includes caregiver support and psychoeducation."},{"id":6,"question":"Did cognitive problems begin alongside depression (sadness, hopelessness, sleep changes, loss of interest)?","yes":7,"no":9,"teach":"Depression can cause significant cognitive impairment that mimics dementia — called pseudodementia."},{"id":7,"outcome":"DEPRESSION WITH COGNITIVE SYMPTOMS (PSEUDODEMENTIA)","color":"#10B981","action":"Treat the depression aggressively (CBT + antidepressant). Cognitive function typically improves as depression lifts.","clinicalNote":"Reversible. Key clues: patient is distressed by cognitive problems (dementia patients often are not), onset tracks with mood episode, \"I don't know\" answers (vs confabulation in dementia)."},{"id":8,"outcome":"MAJOR NCD — OTHER ETIOLOGY","color":"#8B5CF6","action":"Refer for neurological evaluation. Consider vascular, Lewy body, frontotemporal causes based on symptom pattern.","clinicalNote":"Stepwise decline suggests vascular. Visual hallucinations suggest Lewy body. Personality/behavior changes suggest frontotemporal."},{"id":9,"outcome":"MILD NEUROCOGNITIVE DISORDER","color":"#3B82F6","action":"Cognitive rehabilitation, lifestyle modifications (exercise, social engagement, cognitive stimulation). Monitor for progression.","clinicalNote":"Noticeable cognitive decline that does not yet impair independence. May be early dementia or may remain stable."}]},"modalitySelect":{"id":"modalitySelect","title":"Therapy Modality Selection","category":"treatment","domain":"Treatment Planning","description":"Matching the therapeutic approach to the presenting problem and client factors.","whatToNotice":"The diagnosis and presenting problem point to the evidence-based modality. CBT for anxiety/depression, DBT for BPD/emotion dysregulation, EMDR/CPT/PE for trauma, MI for ambivalence.","whyItMatters":"The NCMHCE rewards matching the intervention to the evidence base. \"Generic supportive therapy\" when a specific protocol exists is scored as a weaker answer.","goldenFormula":"Validate the client, explore what the core problem is (mood, behavior, trauma, relational, identity), then act by selecting the modality with the strongest evidence for that problem.","startId":1,"nodes":[{"id":1,"question":"Is the primary problem a trauma/PTSD presentation?","yes":2,"no":3,"teach":"Trauma-focused therapies have the strongest evidence for PTSD — stronger than generic CBT or supportive therapy."},{"id":2,"outcome":"TRAUMA-FOCUSED THERAPY","color":"#8B5CF6","action":"CPT, PE, or EMDR. Stabilization before processing. All three have strong evidence; client preference matters.","clinicalNote":"CPT is most cognitive, PE is most exposure-based, EMDR uses bilateral stimulation. All are effective for PTSD."},{"id":3,"question":"Is the primary problem emotion dysregulation, self-harm, or borderline personality features?","yes":4,"no":5,"teach":"DBT was designed specifically for emotion dysregulation and BPD. It has the strongest evidence for these presentations."},{"id":4,"outcome":"DBT","color":"#EF4444","action":"Full DBT: individual therapy + skills group + phone coaching + consultation team. Skills: mindfulness, distress tolerance, emotion regulation, interpersonal effectiveness.","clinicalNote":"DBT is the gold standard for BPD and chronic suicidality. Partial DBT (skills only) is less effective than the full model."},{"id":5,"question":"Is the primary problem anxiety, depression, or a specific behavioral pattern (phobia, insomnia, panic)?","yes":6,"no":7,"teach":"CBT has the broadest evidence base across anxiety and mood disorders. Specific CBT protocols exist for each condition."},{"id":6,"outcome":"CBT (CONDITION-SPECIFIC)","color":"#3B82F6","action":"Match the CBT protocol to the condition: ERP for OCD, interoceptive exposure for panic, behavioral activation for depression, CBT-I for insomnia.","clinicalNote":"Not generic CBT — the exam rewards naming the specific protocol. \"CBT with exposure\" for anxiety, \"CBT with behavioral activation\" for depression."},{"id":7,"question":"Is the client ambivalent about change or in a precontemplation/contemplation stage?","yes":8,"no":9,"teach":"Motivational interviewing is the evidence-based approach for ambivalence, particularly in substance use and health behavior change."},{"id":8,"outcome":"MOTIVATIONAL INTERVIEWING","color":"#10B981","action":"MI: OARS (Open questions, Affirmations, Reflections, Summaries). Develop discrepancy. Roll with resistance. Support self-efficacy.","clinicalNote":"MI is for ambivalence, not for action-stage clients. Once motivation is established, transition to an active treatment modality."},{"id":9,"question":"Is the primary problem interpersonal (grief, role transitions, relationship conflict)?","yes":10,"no":11,"teach":"IPT was designed for depression in the context of interpersonal problems — grief, role disputes, role transitions, and interpersonal deficits."},{"id":10,"outcome":"INTERPERSONAL THERAPY (IPT)","color":"#F59E0B","action":"IPT: identify the interpersonal problem area, work through communication patterns and relationship expectations.","clinicalNote":"IPT is time-limited and focused on current relationships. Strong evidence for depression, bulimia, and perinatal mood disorders."},{"id":11,"outcome":"ASSESS AND MATCH","color":"#6B7280","action":"Consider psychodynamic for personality and relational patterns, ACT for chronic pain/acceptance, or solution-focused for brief, goal-directed work.","clinicalNote":"When no specific protocol fits, client factors (preference, psychological mindedness, goals) guide the choice."}]},"medReferral":{"id":"medReferral","title":"When to Refer for Medication","category":"treatment","domain":"Treatment Planning","description":"Deciding when psychotherapy alone is sufficient versus when a medication referral to a prescriber is indicated.","whatToNotice":"Severity, safety risk, functional impairment, and whether the condition has strong medication evidence. Moderate-severe mood/psychotic/bipolar presentations generally warrant medication consultation.","whyItMatters":"Counselors do not prescribe, but knowing WHEN to refer for medication is a core competency tested on the NCMHCE. Under-referring leaves treatable symptoms unmanaged; over-referring undermines client autonomy.","goldenFormula":"Validate the client experience, explore severity and functional impact, then act by making the referral when the clinical picture warrants it — and explaining why.","startId":1,"nodes":[{"id":1,"question":"Is the client experiencing psychotic symptoms (hallucinations, delusions, disorganized thinking)?","yes":2,"no":3,"teach":"Psychotic symptoms almost always require medication. Therapy alone is insufficient for active psychosis."},{"id":2,"outcome":"MEDICATION REFERRAL INDICATED","color":"#EF4444","action":"Refer to psychiatrist for antipsychotic evaluation. Continue therapy as adjunct. Do not delay referral.","clinicalNote":"Active psychosis is not manageable with therapy alone. Antipsychotic medication is first-line, therapy is adjunct."},{"id":3,"question":"Is there a current manic or hypomanic episode?","yes":2,"no":4,"teach":"Mood stabilizers and/or antipsychotics are first-line for acute mania. Therapy supports but does not replace medication here."},{"id":4,"question":"Is the presentation moderate-to-severe depression with significant functional impairment?","yes":5,"no":6,"teach":"Mild depression responds well to therapy alone. Moderate-severe often benefits from combined treatment."},{"id":5,"outcome":"RECOMMEND COMBINED TREATMENT","color":"#F59E0B","action":"Refer for SSRI/SNRI evaluation while continuing therapy. Combined treatment (medication + CBT) has better outcomes than either alone for moderate-severe depression.","clinicalNote":"Not an either/or — combined treatment is the strongest evidence-based approach for moderate-severe depression."},{"id":6,"question":"Has the client been in therapy for an adequate trial (8-12 weeks) with insufficient response?","yes":7,"no":8,"teach":"An adequate therapy trial means consistent attendance and engagement over 2-3 months. Insufficient response may warrant medication augmentation."},{"id":7,"outcome":"CONSIDER MEDICATION AUGMENTATION","color":"#F59E0B","action":"Discuss medication referral as augmentation to therapy. Explain the rationale. Respect client autonomy in the decision.","clinicalNote":"Therapy non-response after adequate trial is a reasonable trigger for medication consideration — not a failure of therapy."},{"id":8,"question":"Is the condition one where therapy alone has strong evidence (specific phobia, mild depression, mild-moderate anxiety)?","yes":9,"no":10,"teach":"Some conditions have such strong therapy evidence that medication is rarely needed as first-line."},{"id":9,"outcome":"THERAPY ALONE APPROPRIATE","color":"#10B981","action":"Continue evidence-based therapy. Reassess if symptoms worsen or do not improve after adequate trial.","clinicalNote":"Specific phobia, mild depression, and mild anxiety respond well to therapy alone. Medication is not automatically needed."},{"id":10,"outcome":"CLINICAL JUDGMENT — DISCUSS OPTIONS","color":"#3B82F6","action":"Present both options to the client. Discuss evidence, preferences, side effects, and combined approach. Support informed decision-making.","clinicalNote":"Many conditions fall in a gray area. The counselor role is to inform, not prescribe or withhold referral."}]},"modalityFormat":{"id":"modalityFormat","title":"Individual vs Group vs Family Therapy","category":"treatment","domain":"Treatment Planning","description":"Selecting the treatment format (individual, group, family, or combination) based on the clinical presentation.","whatToNotice":"The problem location. Individual: internal (mood, anxiety, trauma). Group: skills, normalization, interpersonal learning. Family: system dynamics, child/adolescent issues, relational problems.","whyItMatters":"The NCMHCE tests format selection, not just modality. DBT requires a group component. Adolescent conduct disorder is best addressed with family therapy. Grouping antisocial youth worsens outcomes.","goldenFormula":"Validate the presenting concern, explore who is affected and how (individual, relational, systemic), then act by matching the format to the problem level.","startId":1,"nodes":[{"id":1,"question":"Is the client a child or adolescent with behavioral or family-system issues?","yes":2,"no":4,"teach":"Children and adolescents are embedded in family systems. Treating the child alone often misses the maintaining factors."},{"id":2,"question":"Is the primary problem a behavioral disorder (ODD, CD) or family conflict?","yes":3,"no":4,"teach":"MST, FFT, and PCIT all involve the family system — because that is where the maintaining factors are."},{"id":3,"outcome":"FAMILY-BASED TREATMENT","color":"#8B5CF6","action":"MST or FFT for conduct problems. FBT for adolescent eating disorders. PCIT for young children with disruptive behavior.","clinicalNote":"Family involvement is the strongest evidence-based approach for adolescent behavioral disorders and adolescent anorexia."},{"id":4,"question":"Would the client benefit from interpersonal learning, skills practice, universality, and normalization?","yes":5,"no":7,"teach":"Group therapy adds dimensions that individual cannot — learning that others share your experience, practicing skills with peers, receiving feedback."},{"id":5,"question":"Is there a risk that group exposure could worsen the client (e.g., antisocial youth, active substance use peer influence)?","yes":6,"no":8,"teach":"Grouping antisocial youth together (\"deviancy training\") is contraindicated — it worsens outcomes."},{"id":6,"outcome":"INDIVIDUAL PREFERRED OVER GROUP","color":"#F59E0B","action":"Individual therapy to avoid iatrogenic peer effects. Group only if carefully structured and pro-social.","clinicalNote":"Antisocial youth, actively using substance users, and highly acute clients can be harmed by poorly structured groups."},{"id":7,"question":"Is the primary issue internal (mood, anxiety, trauma, identity) without significant relational/systemic factors?","yes":9,"no":10,"teach":"Individual therapy is the default for intrapersonal problems where the work is private and deeply personal."},{"id":8,"outcome":"GROUP THERAPY (ALONE OR COMBINED)","color":"#10B981","action":"DBT skills group, process group, psychoeducation group, or support group depending on the need. Often combined with individual.","clinicalNote":"Group is especially effective for: DBT skills, social anxiety exposure, substance use recovery, grief, and interpersonal learning."},{"id":9,"outcome":"INDIVIDUAL THERAPY","color":"#3B82F6","action":"Match the modality to the condition (CBT, EMDR, psychodynamic, etc.). Standard 1:1 format.","clinicalNote":"Individual is the most flexible format and appropriate default for most intrapersonal presentations."},{"id":10,"outcome":"COMBINATION APPROACH","color":"#10B981","action":"Individual + group, or individual + family. Common for DBT (individual + skills group), adolescent treatment, and substance use.","clinicalNote":"Many evidence-based protocols require combined formats — full DBT is individual + group + phone coaching."}]},"dualRelationship":{"id":"dualRelationship","title":"Dual Relationship / Boundary Decision","category":"ethics","domain":"Professional Practice & Ethics","description":"Evaluating whether a dual relationship is ethically permissible or must be avoided.","whatToNotice":"Power differential, exploitation risk, and whether the dual role is avoidable. Rural and small-community practice makes some dual relationships unavoidable.","whyItMatters":"ACA Code A.5 allows non-harmful dual relationships in some circumstances but prohibits exploitative ones. The exam tests nuanced judgment, not blanket prohibition.","goldenFormula":"Validate the complexity of the situation, explore the potential for harm (power, exploitation, impaired objectivity), then act with the most protective path — consult, document, refer if needed.","startId":1,"nodes":[{"id":1,"question":"Is this a sexual or romantic relationship with a current client?","yes":2,"no":3,"teach":"Sexual/romantic relationships with current clients are NEVER acceptable. This is the one absolute prohibition."},{"id":2,"outcome":"PROHIBITED — NO EXCEPTIONS","color":"#EF4444","action":"Terminate the non-therapeutic relationship immediately. Seek consultation and supervision. Self-report if the boundary has been violated.","clinicalNote":"ACA Code A.5.a: Sexual or romantic relationships with current clients are prohibited. No exceptions, no gray area."},{"id":3,"question":"Is this a sexual or romantic relationship with a former client (within 5 years of last contact)?","yes":4,"no":5,"teach":"ACA prohibits sexual relationships with former clients for 5 years — and even after 5 years, the burden is on the counselor to demonstrate no exploitation."},{"id":4,"outcome":"PROHIBITED","color":"#EF4444","action":"Do not pursue. The 5-year prohibition is clear. After 5 years, consult extensively before considering.","clinicalNote":"ACA A.5.b: 5-year prohibition. Even after 5 years, the counselor must demonstrate the relationship is not exploitative."},{"id":5,"question":"Could the dual relationship cause harm to the client or impair your professional judgment?","yes":6,"no":7,"teach":"The core test: could this hurt the client or compromise your objectivity?"},{"id":6,"outcome":"AVOID OR REFER","color":"#F59E0B","action":"If avoidable, avoid. If unavoidable (rural/small community), document the rationale, consult, and establish clear boundaries.","clinicalNote":"When harm risk exists, the ethical path is avoidance. If truly unavoidable, extensive documentation and consultation are required."},{"id":7,"question":"Is this relationship unavoidable due to community context (rural, military, small town, cultural community)?","yes":8,"no":9,"teach":"Some dual relationships are genuinely unavoidable. The ethical requirement shifts to managing, not avoiding."},{"id":8,"outcome":"MANAGE WITH SAFEGUARDS","color":"#10B981","action":"Document the dual relationship, discuss with client, establish clear boundaries, obtain informed consent, seek ongoing consultation.","clinicalNote":"ACA acknowledges unavoidable dual relationships. The standard is not zero contact but informed management with documentation."},{"id":9,"outcome":"PROCEED WITH CAUTION","color":"#10B981","action":"If not harmful and potentially beneficial, proceed with documentation, informed consent, and consultation.","clinicalNote":"Not all dual relationships are harmful. The ethical analysis is about power, exploitation, and objectivity — not blanket avoidance."}]},"informedConsent":{"id":"informedConsent","title":"Informed Consent & Capacity","category":"ethics","domain":"Professional Practice & Ethics","description":"Evaluating whether a client can provide informed consent and what to do when capacity is in question.","whatToNotice":"Age, cognitive status, legal guardianship, and understanding. Minors, cognitively impaired clients, and court-ordered clients all have different consent considerations.","whyItMatters":"Treatment without valid informed consent is both unethical and potentially illegal. The NCMHCE tests whether you know who can consent, what must be disclosed, and how to handle capacity questions.","goldenFormula":"Validate the client, explore their understanding and capacity (can they understand, appreciate, reason, and express a choice?), then act by obtaining proper consent or involving appropriate parties.","startId":1,"nodes":[{"id":1,"question":"Is the client a minor (under 18)?","yes":2,"no":4,"teach":"Minors generally cannot consent independently. Parent/guardian consent is typically required, with the minor providing assent."},{"id":2,"question":"Does the minor meet an exception (emancipated, mature minor, or state-specific exception for substance/mental health treatment)?","yes":3,"no":10,"teach":"Some states allow minors to consent independently for substance abuse, mental health, or reproductive health services."},{"id":3,"outcome":"MINOR CAN CONSENT INDEPENDENTLY","color":"#10B981","action":"Obtain consent from the minor. Document the legal basis for independent consent. Balance confidentiality with safety.","clinicalNote":"Emancipated minors and state-specific exceptions allow independent consent. Know your state law."},{"id":4,"question":"Does the client appear to understand the nature, risks, benefits, and alternatives of treatment?","yes":5,"no":6,"teach":"The four elements of capacity: understanding, appreciation, reasoning, and expressing a choice."},{"id":5,"outcome":"STANDARD INFORMED CONSENT","color":"#10B981","action":"Provide full disclosure: nature of services, risks/benefits, limits of confidentiality, fees, right to refuse. Document consent.","clinicalNote":"Standard consent requires disclosure of all material information. Ongoing process — not a one-time form."},{"id":6,"question":"Is the impaired capacity due to an acute condition (intoxication, psychotic episode, delirium)?","yes":7,"no":8,"teach":"Acute impairment may be temporary — capacity should be reassessed when the condition resolves."},{"id":7,"outcome":"DEFER NON-EMERGENCY CONSENT","color":"#F59E0B","action":"Provide emergency stabilization if needed. Defer non-emergency treatment decisions until capacity is restored. Document.","clinicalNote":"Acute intoxication or psychosis temporarily impairs capacity. Reassess when the client is stabilized."},{"id":8,"question":"Is there a legal guardian or healthcare proxy with authority to consent?","yes":9,"no":11,"teach":"Court-appointed guardians or healthcare proxies may consent on behalf of incapacitated adults."},{"id":9,"outcome":"OBTAIN SUBSTITUTE CONSENT","color":"#F59E0B","action":"Obtain consent from the legal guardian/proxy. Still involve the client to the extent of their capacity (assent). Document.","clinicalNote":"Even with substitute consent, involve the client in decisions as much as their capacity allows."},{"id":10,"outcome":"OBTAIN PARENTAL CONSENT + MINOR ASSENT","color":"#F59E0B","action":"Parent/guardian provides legal consent. Obtain the minor's assent (age-appropriate agreement). Discuss confidentiality limits with both.","clinicalNote":"Balance parental right to information with the therapeutic alliance. Negotiate confidentiality boundaries at the outset."},{"id":11,"outcome":"SEEK CAPACITY EVALUATION","color":"#F59E0B","action":"Refer for formal capacity evaluation if uncertain. Consult ethics board or legal counsel. Do not proceed with treatment requiring consent until resolved.","clinicalNote":"When capacity is unclear and no proxy exists, formal evaluation protects both the client and the clinician."}]},"dissociative":{"id":"dissociative","title":"Dissociative Disorder Differential","category":"differential","domain":"Assessment & Diagnosis","description":"Distinguishing DID, depersonalization/derealization, dissociative amnesia, and trauma-related dissociation from psychosis.","whatToNotice":"Identity disruption vs detachment vs memory gaps. DID has distinct identity states. DPDR has detachment without identity fragmentation. Key: dissociation is NOT psychosis — dissociative voices are internal.","whyItMatters":"Dissociative symptoms are frequently misdiagnosed as psychosis, leading to inappropriate antipsychotic treatment. The exam tests whether you can differentiate dissociative experiences from psychotic hallucinations.","goldenFormula":"Validate the experience without pathologizing, explore the nature of symptoms (identity disruption, detachment, memory gaps, voices — internal or external?), then act with the trauma-informed approach the diagnosis requires.","startId":1,"nodes":[{"id":1,"question":"Are there two or more distinct personality states with disruption of identity, consciousness, memory, and behavior?","yes":2,"no":4,"teach":"DID requires distinct identity states that recurrently take control — not just mood shifts or role changes."},{"id":2,"question":"Are there recurrent gaps in recall for everyday events or personal information beyond ordinary forgetting?","yes":3,"no":4,"teach":"Amnesia between identity states is a hallmark of DID."},{"id":3,"outcome":"DISSOCIATIVE IDENTITY DISORDER","color":"#8B5CF6","action":"Phase-oriented trauma therapy: stabilization, trauma processing, integration. Do NOT force integration. Avoid hypnosis for memory recovery.","clinicalNote":"DID voices are internal and recognized as part of the self — unlike psychotic hallucinations which are external. Never treat DID with antipsychotics alone."},{"id":4,"question":"Are there persistent experiences of detachment from mind, body, or surroundings (feeling unreal, dreamlike)?","yes":5,"no":6,"teach":"Depersonalization (self feels unreal) and derealization (world feels unreal) are detachment without identity fragmentation."},{"id":5,"outcome":"DEPERSONALIZATION/DEREALIZATION DISORDER","color":"#3B82F6","action":"CBT targeting catastrophic interpretations of dissociative experiences. Grounding techniques. Address comorbid anxiety/depression.","clinicalNote":"Reality testing is intact — the person KNOWS the experience is not real, distinguishing it from psychosis."},{"id":6,"question":"Is the primary symptom inability to recall important autobiographical information, usually traumatic?","yes":7,"no":8,"teach":"Dissociative amnesia is memory loss for specific events — not global identity disruption."},{"id":7,"outcome":"DISSOCIATIVE AMNESIA","color":"#F59E0B","action":"Supportive therapy in a safe environment. Do NOT use hypnosis or memory recovery techniques — risk of false memories.","clinicalNote":"Memory may return spontaneously when safety is established. Dissociative fugue is a specifier (travel + identity confusion)."},{"id":8,"question":"Do dissociative experiences occur exclusively during PTSD flashbacks or trauma re-experiencing?","yes":9,"no":10,"teach":"Dissociation during trauma re-experiencing is a feature of PTSD dissociative subtype, not a separate disorder."},{"id":9,"outcome":"PTSD WITH DISSOCIATIVE FEATURES","color":"#F59E0B","action":"Trauma-focused therapy with additional stabilization for dissociation. Grounding before exposure work.","clinicalNote":"PTSD dissociative subtype. Standard PTSD protocols with additional grounding and stabilization."},{"id":10,"outcome":"ASSESS FURTHER","color":"#6B7280","action":"Rule out substance-induced dissociation, seizure disorders, and malingering. Comprehensive trauma history.","clinicalNote":"Dissociative symptoms without a clear pattern. Medical causes must be ruled out."}]},"sudSeverity":{"id":"sudSeverity","title":"Substance Use Disorder Severity & Level of Care","category":"differential","domain":"Assessment & Diagnosis","description":"Determining SUD severity (mild, moderate, severe) and matching to appropriate treatment intensity.","whatToNotice":"Count DSM-5 criteria met (2-3 mild, 4-5 moderate, 6+ severe). Then assess safety: withdrawal risk, medical complications, environmental support.","whyItMatters":"Severity determines level of care. Mild SUD with support may need outpatient only. Severe SUD with medical risk needs detox. The NCMHCE tests both diagnosis and placement.","goldenFormula":"Validate without judgment, explore the full pattern (quantity, frequency, consequences, failed attempts, withdrawal history), then act by matching treatment intensity to severity and safety.","startId":1,"nodes":[{"id":1,"question":"Does the person meet 2 or more DSM-5 SUD criteria (impaired control, social impairment, risky use, pharmacological)?","yes":2,"no":8,"teach":"SUD requires 2+ of 11 criteria. Below 2 is problematic use but not diagnosable."},{"id":2,"question":"Are 6 or more criteria met?","yes":3,"no":5,"teach":"6+ criteria = severe. Intensive treatment is almost always indicated."},{"id":3,"question":"Is the substance one with medically dangerous withdrawal (alcohol, benzodiazepines)?","yes":4,"no":9,"teach":"Severe SUD with dangerous withdrawal = medical detox first."},{"id":4,"outcome":"SEVERE SUD — MEDICAL DETOX + RESIDENTIAL/IOP","color":"#EF4444","action":"Medically supervised detox first. Then residential or IOP. MAT for opioid/alcohol. Long-term recovery support.","clinicalNote":"Severe + dangerous withdrawal = highest level of care. ASAM criteria guide placement. MAT reduces relapse and mortality."},{"id":5,"question":"Are 4-5 criteria met?","yes":6,"no":7,"teach":"4-5 criteria = moderate. Intensity depends on functional impairment and support."},{"id":6,"outcome":"MODERATE SUD — IOP OR STRUCTURED OUTPATIENT","color":"#F59E0B","action":"IOP (3-5 days/week) or structured outpatient with MI + CBT/relapse prevention. Consider MAT. Group therapy beneficial.","clinicalNote":"Moderate severity responds well to IOP. MI addresses ambivalence; CBT addresses triggers."},{"id":7,"outcome":"MILD SUD — OUTPATIENT","color":"#10B981","action":"Weekly outpatient. MI + brief interventions. Psychoeducation. Self-help groups as adjunct.","clinicalNote":"Mild SUD (2-3 criteria) in supportive environment responds to outpatient. Monitor for escalation."},{"id":8,"outcome":"PROBLEMATIC USE — NOT SUD","color":"#3B82F6","action":"Brief intervention, psychoeducation, harm reduction. Monitor. Address underlying issues.","clinicalNote":"Below diagnostic threshold but concerning. Brief interventions appropriate."},{"id":9,"outcome":"SEVERE SUD — RESIDENTIAL OR INTENSIVE OUTPATIENT","color":"#EF4444","action":"Residential or intensive outpatient depending on support system and co-occurring disorders. MAT as appropriate.","clinicalNote":"Severe SUD without dangerous withdrawal still needs intensive treatment but medical detox may not be required."}]},"termination":{"id":"termination","title":"Termination & Referral Decision","category":"ethics","domain":"Professional Practice & Ethics","description":"Deciding when and how to end the therapeutic relationship — planned completion, client-initiated, or counselor-initiated.","whatToNotice":"Reason for ending: goals met, client not benefiting, outside scope, boundary issue, or client disappearance. Each pathway has different ethical obligations.","whyItMatters":"The NCMHCE tests both when termination is appropriate and how to handle it ethically. Abandonment (terminating without ensuring continuity) is an ethical violation.","goldenFormula":"Validate the therapeutic work done, explore the reason for ending, then act with proper transition — referrals, summary, and the door left open.","startId":1,"nodes":[{"id":1,"question":"Have the client's treatment goals been substantially met?","yes":2,"no":3,"teach":"Goal completion is the ideal reason for termination — a therapeutic success."},{"id":2,"outcome":"PLANNED TERMINATION","color":"#10B981","action":"Review progress, consolidate gains, develop relapse prevention plan, discuss future needs, leave door open.","clinicalNote":"The gold standard. Termination is a process — several sessions of preparation, not abrupt."},{"id":3,"question":"Is the client not benefiting despite adequate effort and modality adjustments?","yes":4,"no":5,"teach":"Continuing non-beneficial treatment is not ethical. The obligation is to refer."},{"id":4,"outcome":"REFER TO BETTER-FIT PROVIDER","color":"#F59E0B","action":"Discuss openly. Provide at least 3 referral options. Offer to coordinate transfer. Document rationale.","clinicalNote":"ACA A.11.a: Counselors do not abandon clients. Non-benefit termination requires referrals and warm handoff."},{"id":5,"question":"Is the issue outside your scope of competence or licensure?","yes":6,"no":7,"teach":"Practicing outside scope is an ethical and legal violation. Refer appropriately."},{"id":6,"outcome":"REFER FOR SCOPE/COMPETENCE","color":"#F59E0B","action":"Explain reason without oversharing. Provide referrals. Continue care until transfer is complete.","clinicalNote":"Scope-based referral is ethical, not rejection. Frame as getting the client the best possible care."},{"id":7,"question":"Is there a boundary issue making continued treatment inadvisable?","yes":8,"no":9,"teach":"Some situations require counselor-initiated termination to protect the client or the therapeutic frame."},{"id":8,"outcome":"COUNSELOR-INITIATED TERMINATION WITH REFERRAL","color":"#F59E0B","action":"Consult supervisor. Discuss with client at appropriate level. Provide referrals. Document thoroughly.","clinicalNote":"The counselor can end treatment when continuing would be harmful — but must ensure continuity of care."},{"id":9,"question":"Has the client stopped attending without explanation?","yes":10,"no":11,"teach":"Client disappearance requires follow-up attempts before closing the case."},{"id":10,"outcome":"OUTREACH THEN ADMINISTRATIVE CLOSURE","color":"#3B82F6","action":"Make documented outreach attempts. After reasonable attempts, send termination letter leaving door open. Close file.","clinicalNote":"Document all outreach. The termination letter should express care and provide crisis resources."},{"id":11,"outcome":"CONTINUE TREATMENT — REASSESS GOALS","color":"#10B981","action":"No termination triggers present. Reassess and update goals collaboratively.","clinicalNote":"No termination indicated. Continue with updated goals and ongoing progress assessment."}]},"culturalDx":{"id":"culturalDx","title":"Cultural Considerations in Diagnosis","category":"differential","domain":"Assessment & Diagnosis","description":"Evaluating whether cultural, spiritual, or contextual factors explain symptoms that might otherwise be pathologized.","whatToNotice":"Cultural norms for emotional expression, spiritual experiences, bereavement practices, and help-seeking behavior. What looks like pathology in one framework may be normative in another.","whyItMatters":"The NCMHCE tests cultural competence in diagnosis. Pathologizing culturally normative experiences (e.g., hearing a deceased relative's voice in some cultures) is a diagnostic error. So is missing genuine pathology by over-attributing to culture.","goldenFormula":"Validate the cultural framework, explore symptoms within that context (distress, impairment, cultural norm), then act with a culturally informed diagnosis — neither pathologizing nor dismissing.","startId":1,"nodes":[{"id":1,"question":"Are the symptoms consistent with culturally normative experiences (spiritual visions, ancestor communication, culturally expected grief)?","yes":2,"no":5,"teach":"The DSM-5 Cultural Formulation Interview helps distinguish cultural experiences from psychopathology."},{"id":2,"question":"Is the person distressed by or impaired by these experiences?","yes":3,"no":4,"teach":"Cultural experiences that cause distress may still warrant clinical attention — even if culturally normative."},{"id":3,"outcome":"CULTURALLY INFORMED CLINICAL ASSESSMENT","color":"#F59E0B","action":"Use DSM-5 Cultural Formulation Interview. Consult cultural brokers or community leaders. Consider both cultural context AND clinical significance.","clinicalNote":"Distress within a cultural experience does not automatically make it pathology — but does require clinical attention."},{"id":4,"outcome":"CULTURALLY NORMATIVE — NOT PATHOLOGICAL","color":"#10B981","action":"Do not diagnose. Validate the cultural framework. If seeking support for other reasons, address those. Document cultural context.","clinicalNote":"Hearing a deceased loved one during grief, spiritual visions during prayer, trance states in ceremonies — these are not psychosis."},{"id":5,"question":"Could the presentation reflect a cultural idiom of distress (e.g., nervios, ataques de nervios, somatic complaints for emotional distress)?","yes":6,"no":7,"teach":"Cultural idioms express suffering through culturally shaped patterns that may not map directly to DSM categories."},{"id":6,"outcome":"ASSESS THROUGH CULTURAL LENS","color":"#3B82F6","action":"Understand the idiom. Identify the underlying condition using culturally sensitive assessment. Engage cultural consultants.","clinicalNote":"Nervios may encompass anxiety, depression, and somatization. Treatment should address underlying distress, not just presentation."},{"id":7,"question":"Is there risk of underdiagnosis — dismissing genuine symptoms as just cultural?","yes":8,"no":9,"teach":"Over-attributing to culture is as harmful as under-attributing. Psychosis, depression, and PTSD occur across all cultures."},{"id":8,"outcome":"DIAGNOSE WITH CULTURAL SENSITIVITY","color":"#F59E0B","action":"Apply diagnostic criteria while documenting cultural context. Cultural factors shape presentation but do not eliminate pathology.","clinicalNote":"A person from any culture can develop schizophrenia, depression, or PTSD. Cultural humility means seeing the person AND their context."},{"id":9,"outcome":"STANDARD DIAGNOSTIC PROCESS","color":"#3B82F6","action":"Proceed with standard assessment. Incorporate cultural factors into treatment planning (language, values, family structure).","clinicalNote":"Cultural competence shapes the therapeutic relationship, communication style, treatment goals, and family involvement."}]}};
export const DT_CATEGORIES=[{"id":"safety","label":"Safety & Triage","blurb":"Always assessed first — safety gates every other decision."},{"id":"differential","label":"Differential Diagnosis","blurb":"Sorting look-alike presentations to the right diagnosis."},{"id":"ethics","label":"Ethics & Legal","blurb":"When and how the limits of confidentiality apply."},{"id":"treatment","label":"Treatment Selection","blurb":"Matching the intervention to the presentation and the evidence."}];
